class ProbabilisticDecoder(nn.Module):
    """
    Decodes z into the parameters of p_θ(x|z).
    For binary data: returns Bernoulli logits.
    For continuous data: returns Gaussian mean (with fixed σ²=1).
    """
    def __init__(self, z_dim, hidden_dim, x_dim, output='bernoulli'):
        super().__init__()
        self.output = output
        self.net = nn.Sequential(
            nn.Linear(z_dim, hidden_dim), nn.SiLU(),
            nn.Linear(hidden_dim, hidden_dim), nn.SiLU(),
            nn.Linear(hidden_dim, x_dim),     # no final activation — return raw logits/mean
        )

    def forward(self, z):
        return self.net(z)     # logits (Bernoulli) or mean (Gaussian)

    def log_prob(self, z, x):
        """log p_θ(x|z) — used in ELBO computation."""
        out = self(z)
        if self.output == 'bernoulli':
            from torch.distributions import Bernoulli
            return Bernoulli(logits=out).log_prob(x).sum(dim=-1)  # (batch,)
        else:
            from torch.distributions import Normal
            return Normal(out, torch.ones_like(out)).log_prob(x).sum(dim=-1)

# Usage
dec = ProbabilisticDecoder(z_dim=20, hidden_dim=512, x_dim=784, output='bernoulli')
z   = torch.randn(32, 20)
x   = torch.randint(0, 2, (32, 784)).float()
log_pxz = dec.log_prob(z, x)   # (32,) — per-sample log-likelihood
print(log_pxz.shape, log_pxz.mean().item())
